insert into "FBG_ANALYTICS"."CASINO"."DBT_RUN_RESULTS"
         (MODEL_EXECUTION_ID,UNIQUE_ID,INVOCATION_ID,GENERATED_AT,CREATED_AT,NAME,MESSAGE,STATUS,RESOURCE_TYPE,EXECUTION_TIME,EXECUTE_STARTED_AT,EXECUTE_COMPLETED_AT,COMPILE_STARTED_AT,COMPILE_COMPLETED_AT,ROWS_AFFECTED,FULL_REFRESH,COMPILED_CODE,FAILURES,QUERY_ID,THREAD_ID,MATERIALIZATION,ADAPTER_RESPONSE) values
    ('b6334721-30b6-4647-b0db-602f87672cae.model.dbt_casino.crm_casino_xtremepush','model.dbt_casino.crm_casino_xtremepush','b6334721-30b6-4647-b0db-602f87672cae','2026-04-09 22:10:19',
  current_timestamp::timestamp
,'crm_casino_xtremepush','SUCCESS 13587188','success','model',55.98269748687744,'2026-04-09T22:08:35.770716Z','2026-04-09T22:09:31.634100Z','2026-04-09T22:08:35.760529Z','2026-04-09T22:08:35.769402Z',13587188,False,'select \n    DATE(c.timestamp) as date,\n    cm.acco_id,\n    c.campaign_id,\n    c.campaign_name,\n    c.category_name,\n    CASE WHEN campaign_name ILIKE ANY (\'%CYOO%\', \'%SUO%\', \'%Day 2%\', \'%RTC%\', \'%OSB%\', \'%100 CC%\', \'%RNF%\', \'%500 FS%\') THEN \'Early Life\'\n         WHEN campaign_name ILIKE ANY (\'%React%\', \'%Drop%\', \'%FanCash%\', \'%Boost%\', \'%EVO%\', \'%FC%\', \'%Sweeps%\', \'%Spin to Win%\', \'%IGT%\', \'%Bet and Get%\', \'%Launch%\', \'%Diamond Rush%\', \'%RAF%\', \'%BG%\', \'%H5%\', \'%Lucky Ladies%\', \'%Reload%\', \'%Sweep%\', \'%Spin-to-Win%\', \'%BetGet%\', \'%Missed%\') THEN \'BAU\'\n         WHEN campaign_name ILIKE ANY (\'%Churn%\', \'%Reactivation%\', \'%First Time%\', \'%Birthday%\', \'%RTC%\') THEN \'Automated\'\n         WHEN campaign_name ILIKE ANY (\'%VCAS%\', \'%VIP%\') THEN \'VIP\'\n    ELSE \'Other\' END as "Campaign Name Category",\n    c.message_type,\n    c.WORKFLOW_ACTION_NAME,\n    coalesce(c.bonus_id,\'N/A\') as bonus_id,\n    coalesce(cm.registration_geolocation_state,\'N/A\') as state,\n    coalesce(cm.product_preference, \'N/A\') as product_preference,\n    COUNT(DISTINCT CASE WHEN interaction_type = \'sent\' THEN c.user_id END) as Sent_Customers,\n    COUNT(DISTINCT CASE WHEN interaction_type = \'open\' THEN c.user_id END) as Open_customers,\n    COUNT(DISTINCT CASE WHEN interaction_type = \'control\' THEN c.user_id END) as Control_customers,\n    COUNT(DISTINCT CASE WHEN interaction_type = \'click\' THEN c.user_id END) as Clicked_cusomers,\n    COUNT(DISTINCT CASE WHEN interaction_type = \'bounce\' THEN c.user_id END) as Bounced_customers,\n    COUNT(DISTINCT CASE WHEN interaction_type = \'failed\' THEN c.user_id END) as Failed_customers,\n    COUNT(DISTINCT eu.email_id) as Opted_Out_Customers\nfrom FBG_SOURCE.XTREMEPUSH.CAMPAIGNS c\ninner join FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART cm\n    on c.user_id = cm.amelco_id\nleft join FBG_SOURCE.XTREMEPUSH.COMBINED_EMAIL_UNSUBSCRIBERS eu \n    on c.email = eu.email_id\nwhere category_name IN (\'Casino Marketing \',\'Marketing Eligible (with Promo)\') \n    and category_name <> \'Transactional Emails\'\n    and cm.is_test_account = 0\n    and DATE(c.timestamp)  >= \'2025-01-01\'\n    \n            AND date(c.DW_LAST_UPDATED) >= (SELECT MAX(DATEADD(\'day\', -2, date)) FROM FBG_ANALYTICS.CASINO.crm_casino_xtremepush)\n    \nGROUP BY ALL',NULL,'01c39a31-0212-644a-24dd-0703193fff7f','Thread-7 (worker)','incremental','{"_message": "SUCCESS 13587188", "code": "SUCCESS", "rows_affected": 13587188, "query_id": "01c39a31-0212-644a-24dd-0703193fff7f", "rows_inserted": 13587188, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}'),('b6334721-30b6-4647-b0db-602f87672cae.model.dbt_casino.crm_casino_model','model.dbt_casino.crm_casino_model','b6334721-30b6-4647-b0db-602f87672cae','2026-04-09 22:10:19',
  current_timestamp::timestamp
,'crm_casino_model','SUCCESS 2279081','success','model',57.06648564338684,'2026-04-09T22:08:35.768118Z','2026-04-09T22:09:32.732933Z','2026-04-09T22:08:35.755776Z','2026-04-09T22:08:35.767480Z',2279081,False,'with casino_revenue_activity AS ( --noqa: disable=all\n    SELECT \n        acco_id,\n        sum(cash_bet_stake) lifetime_casino_handle,\n        sum(total_bet_count) lifetime_casino_bet_count,\n        sum(freespin_bet_stake) lifetime_free_spin_handle,\n        sum(casino_credit_bet_stake) lifetime_casino_credit_handle,\n        sum(ggr) lifetime_casino_ggr,\n        sum(ngr) lifetime_casino_ngr,\n        count(distinct case when cash_bet_stake > 0 then settled_date_alk else null end) lifetime_casino_cash_player_days,\n        count(distinct case when total_stake > 0 then settled_date_alk else null end) lifetime_casino_player_days,\n        floor(\n            div0(\n                count(distinct case when total_stake > 0 then settled_date_alk else null end),\n                count(distinct case when total_stake > 0 then date_trunc(\'week\',settled_date_alk) else null end)\n            )\n        ) avg_weekly_casino_player_days\n    FROM FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_DAILY_SETTLED_AGG\n    where is_test_account = 0\n    GROUP BY 1\n),\n\ncasino_engagement_activity AS (\n    SELECT \n        acco_id,\n        convert_timezone(\'UTC\',\'America/New_York\',MAX(CASE WHEN fund_type_id = 1 AND stake > 0 THEN placed_time_utc end)) last_casino_cash_bet_date,\n        convert_timezone(\'UTC\',\'America/New_York\',MAX(CASE WHEN stake > 0 THEN placed_time_utc end)) last_casino_bet_date,\n        div0(\n            sum(case when placed_time_utc > dateadd(day, -30,  sysdate()) and fund_type_id <> 1 then payout else 0 end),\n            sum(case when placed_time_utc > dateadd(day, -30,  sysdate()) and fund_type_id = 1 then stake - payout else 0 end)\n        ) as l30d_casino_rtc\n\n    FROM FBG_ANALYTICS_ENGINEERING.CASINO.CASINO_TRANSACTIONS_MART\n    WHERE test = 0 AND void = 0\n    group by 1\n),\n\ncasino_first_year_value AS (\n    SELECT acco_id, first_year_pred_ngr casino_first_year_pred_ngr\n    FROM FBG_ANALYTICS.PRODUCT_AND_CUSTOMER.FIRST_YEAR_OC_LTV_PREDICTIONS\n    WHERE pred_no = 1\n),\n\ncasino_churn_preds as (\n    select \n        acco_id,\n         case when churn_prob >= 0.7 then 1 else 0 end as casino_churn_risk\n    from (\n        select \n            cp.account_id as acco_id, \n            cp.prediction as churn_prob, \n            cp.date, \n            datediff(day, date(cea.last_casino_cash_bet_date), cp.date) days_since_last_bet, \n            row_number() over (partition by cp.account_id order by cp.date desc) rk\n        from FBG_MARTS.CUSTOMERS_MART.CASINO_CHURN_PREDICTIONS AS cp\n        inner join casino_engagement_activity cea\n        on cp.account_id = cea.acco_id\n        where cp.date >= dateadd(day, - 3, sysdate())\n        qualify rk = 1\n    )\n),\n\nf2p_engagement as (\n    select distinct \n        acco_id, \n        max(1) lifetime_has_played_f2p,\n        max(case when date(convert_timezone(\'UTC\',\'America/New_York\',time_awarded)) = date(convert_timezone(\'UTC\',\'America/New_York\',sysdate())) \n                 then 1 \n                 else 0 end) today_has_played_f2p\n    from FBG_SOURCE.OSB_SOURCE.F2P_GAME_SESSION_RESULTS\n    group by 1\n),\n\ncasino_bonus_balances as (\n    SELECT\n        acco_id,\n        max(case when fund_type_id = 17 then balance else 0 end) free_spin_balance,\n        max(case when fund_type_id = 18 then balance else 0 end) casino_credit_balance\n    FROM\n        FBG_SOURCE.OSB_SOURCE.ACCOUNT_BALANCES \n    where fund_type_id in (17,18)\n    group by 1\n),\n\nplatform_usage as (\n    with events as (\n        select user_id as acco_id, coalesce(product, \'Sportsbook App\') product, \'Login\' as event, login_time_utc as start_time_utc\n        from FBG_ANALYTICS.PRODUCT.USER_LOGIN_BY_PRODUCT\n        union all\n        select user_id as acco_id, coalesce(product, \'Sportsbook App\') product, \'Registration\' as event, reg_start_time_utc as start_time_utc\n        from FBG_ANALYTICS.PRODUCT.USER_REG_BY_PRODUCT\n    ),\n\n    first_and_last_platform as (\n        select\n            acco_id,\n            max(case when first_rk = 1 then product end) as registration_platform,\n            max(case when last_rk = 1 then product end) as most_recent_platform,\n            max(case when product = \'Sportsbook App\' then 1 else 0 end) as used_sportsbook_app,\n            max(case when product = \'Casino App\' then 1 else 0 end) as used_casino_app,\n            max(case when product = \'Web\' then 1 else 0 end) as used_web_app\n        from (\n            select \n                acco_id,\n                product,\n                row_number() over (partition by acco_id order by start_time_utc asc) first_rk,\n                row_number() over (partition by acco_id order by start_time_utc desc) last_rk,\n            from events\n            qualify first_rk = 1 or last_rk = 1\n        )\n        group by 1\n    )\n\n    select \n        acco_id,\n        registration_platform,\n        most_recent_platform,\n        used_sportsbook_app,\n        used_casino_app,\n        used_web_app\n    from first_and_last_platform\n),\n\nfancash_jackpots as (\n    with fc_jp_opt_in_history as (\n        SELECT \n            acco_id,\n            CONVERT_TIMEZONE(\'UTC\',\'America/New_York\', change_timestamp)       as change_timestamp_est,\n            is_opted_in,\n            contribution_percentage,\n            row_number() over (partition by acco_id order by change_timestamp desc) rk\n        FROM FBG_SOURCE.OSB_SOURCE.FANCASH_JACKPOT_OPTIN_HISTORY\n    )\n\n    select \n        acco_id,\n        max(case when rk = 1 then change_timestamp_est end) as fc_jackpot_opt_in_status_change_timestamp,\n        max(case when rk = 1 then is_opted_in::int end) as fc_jackpot_current_opt_in,\n        max(is_opted_in::int) as fc_jackpot_lifetime_opt_in,\n        max(case when rk = 1 then contribution_percentage end) as fc_jackpot_contribution_pct\n    from fc_jp_opt_in_history\n    group by 1\n),\n\nlast_30d_max_casino_tier as (\n    select\n        acco_id,\n        max(casino_tier) as best_casino_tier_l30d\n    from FBG_ANALYTICS.CASINO.casino_segments_historical\n    where date >= date(dateadd(day, -30, sysdate()))\n    group by all\n)\n\n\nSELECT \n    cm.acco_id, \n    cm.current_casino_segment, \n    cm.max_casino_segment as best_casino_segment, \n    cm.casino_cluster,\n    cra.lifetime_casino_handle,\n    cra.lifetime_casino_bet_count,\n    cra.lifetime_free_spin_handle,\n    cra.lifetime_casino_credit_handle,\n    cra.lifetime_casino_ggr,\n    cra.lifetime_casino_ngr,\n    cra.lifetime_casino_cash_player_days,\n    cra.lifetime_casino_player_days,\n    cra.avg_weekly_casino_player_days,\n    cm.casino_ftcu_date_est as casino_ftcu_date,\n    cea.last_casino_cash_bet_date,\n    cm.casino_ftu_date_est as casino_ftu_date,\n    cea.last_casino_bet_date,\n    cltv.casino_first_year_pred_ngr,\n    nvl(cp.casino_churn_risk,0) casino_churn_risk,\n    nvl(f2p.lifetime_has_played_f2p,0) lifetime_has_played_f2p,\n    nvl(f2p.today_has_played_f2p,0) today_has_played_f2p,\n    nvl(cbb.free_spin_balance,0) free_spin_balance,\n    nvl(cbb.casino_credit_balance,0) casino_credit_balance,\n    nvl(cea.l30d_casino_rtc,0) l30d_casino_rtc,\n    cm.current_casino_segment_tier,\n    cm.max_casino_segment_tier as best_casino_segment_tier,\n    cm.current_casino_tier,\n    cm.max_casino_tier as best_casino_tier,\n    cm.max_casino_value as best_casino_value,\n    cm.current_casino_value, \n    coalesce(pu.registration_platform,\'Sportsbook App\') registration_platform,\n    coalesce(pu.most_recent_platform,\'Sportsbook App\') most_recent_platform,\n    nvl(pu.used_sportsbook_app,1) used_sportsbook_app,\n    nvl(pu.used_casino_app,0) used_casino_app,\n    nvl(pu.used_web_app,0) used_web_app,\n    cm.product_preference,\n    fcjp.fc_jackpot_opt_in_status_change_timestamp,\n    nvl(fcjp.fc_jackpot_current_opt_in, 0) fc_jackpot_current_opt_in,\n    nvl(fcjp.fc_jackpot_lifetime_opt_in, 0) as fc_jackpot_lifetime_opt_in,\n    nvl(fcjp.fc_jackpot_contribution_pct, 0) fc_jackpot_contribution_pct,\n    mct.best_casino_tier_l30d\nFROM FBG_ANALYTICS_ENGINEERING.CUSTOMERS.CUSTOMER_MART cm\nLEFT JOIN casino_revenue_activity cra\nON cm.acco_id = cra.acco_id\nLEFT JOIN casino_engagement_activity cea\nON cm.acco_id = cea.acco_id\nLEFT JOIN casino_first_year_value cltv\non cm.acco_id = cltv.acco_id\nleft join casino_churn_preds cp\non cm.acco_id = cp.acco_id\nleft join f2p_engagement f2p\non cm.acco_id = f2p.acco_id\nleft join casino_bonus_balances cbb\non cm.acco_id = cbb.acco_id\nleft join platform_usage pu\non cm.acco_id = pu.acco_id\nleft join fancash_jackpots fcjp\non cm.acco_id = fcjp.acco_id\nleft join last_30d_max_casino_tier mct\non cm.acco_id = mct.acco_id\nWHERE (cm.registration_state in (\'MI\',\'NJ\',\'PA\',\'WV\') or cm.has_bet_in_oc_state = 1)\n    and cm.is_test_account = 0',NULL,'01c39a30-0212-6cb9-24dd-0703193fb7db','Thread-6 (worker)','table','{"_message": "SUCCESS 2279081", "code": "SUCCESS", "rows_affected": 2279081, "query_id": "01c39a30-0212-6cb9-24dd-0703193fb7db", "rows_inserted": 2279081, "rows_deleted": 0, "rows_updated": 0, "rows_duplicates": 0}')
